public class Test { public static void main(String[] args) { int radius = 5; int r2 = radius*radius; for(int dx=-radius; dx<=radius; dx++){ for(int dy=-radius; dy<=radius; dy++){ for(int dz=-radius; dz<=radius; dz++){ if(dx*dx+dy*dy+dz*dz<=r2) { if (dy <= 0) { boolean isFloor = (dy == -radius) || (dx*dx+(dy-1)*(dy-1)+dz*dz > r2); if(isFloor) { System.out.println(dx + ", "+ dy + ", "+ dz + " is floor"); } } } } } } } }
